import React, { useState } from 'react';
import { useBrand } from '../context/BrandContext';
import { useToast } from './ui/Toast';
import { ResumeProfile } from '../hooks/useResumeProfiles';

interface ResumeProfileManagerProps {
  profiles: ResumeProfile[];
  onClose: () => void;
  onCreate: (profile: { name: string; target_role: string; resume_text: string; is_default?: boolean }) => Promise<ResumeProfile | null>;
  onUpdate: (id: string, updates: Partial<Pick<ResumeProfile, 'name' | 'target_role' | 'resume_text' | 'is_default'>>) => Promise<boolean>;
  onDelete: (id: string) => Promise<boolean>;
}

export default function ResumeProfileManager({ profiles, onClose, onCreate, onUpdate, onDelete }: ResumeProfileManagerProps) {
  const brand = useBrand();
  const { showToast } = useToast();
  const [editingId, setEditingId] = useState<string | null>(null);
  const [showCreate, setShowCreate] = useState(false);

  // Form state
  const [formName, setFormName] = useState('');
  const [formRole, setFormRole] = useState('');
  const [formText, setFormText] = useState('');
  const [formDefault, setFormDefault] = useState(false);
  const [saving, setSaving] = useState(false);

  function startEdit(p: ResumeProfile) {
    setEditingId(p.id);
    setFormName(p.name);
    setFormRole(p.target_role);
    setFormText(p.resume_text);
    setFormDefault(p.is_default);
    setShowCreate(false);
  }

  function startCreate() {
    setEditingId(null);
    setFormName('');
    setFormRole('');
    setFormText('');
    setFormDefault(false);
    setShowCreate(true);
  }

  function cancelForm() {
    setEditingId(null);
    setShowCreate(false);
  }

  async function handleSave() {
    if (!formName.trim()) {
      showToast('Profile name is required.', true);
      return;
    }
    if (!formText.trim()) {
      showToast('Resume text is required.', true);
      return;
    }

    setSaving(true);

    if (showCreate) {
      const result = await onCreate({
        name: formName.trim(),
        target_role: formRole.trim(),
        resume_text: formText.trim(),
        is_default: formDefault,
      });
      if (result) {
        showToast('Profile created!');
        cancelForm();
      } else {
        showToast('Failed to create profile.', true);
      }
    } else if (editingId) {
      const ok = await onUpdate(editingId, {
        name: formName.trim(),
        target_role: formRole.trim(),
        resume_text: formText.trim(),
        is_default: formDefault,
      });
      if (ok) {
        showToast('Profile updated!');
        cancelForm();
      } else {
        showToast('Failed to update profile.', true);
      }
    }

    setSaving(false);
  }

  async function handleDelete(id: string) {
    const ok = await onDelete(id);
    if (ok) {
      showToast('Profile deleted.');
      if (editingId === id) cancelForm();
    } else {
      showToast('Failed to delete profile.', true);
    }
  }

  const isFormOpen = showCreate || editingId !== null;

  return (
    <div
      className="modal-overlay"
      onClick={(e) => { if (e.target === e.currentTarget) onClose(); }}
    >
      <div className="modal-dialog md">
        <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginBottom: '1.5rem' }}>
          <h3 style={{ margin: 0, color: 'var(--text-primary)', fontSize: '1.1rem' }}>
            <i className="fa-solid fa-user-tie" style={{ color: brand.primaryColor, marginRight: '0.5rem' }} />
            Resume Profiles
          </h3>
          <button onClick={onClose} className="icon-btn" style={{ color: 'var(--text-secondary)', fontSize: '1.1rem' }}>
            <i className="fa-solid fa-xmark" />
          </button>
        </div>

        {/* Profile List */}
        {!isFormOpen && (
          <>
            {profiles.length === 0 ? (
              <p style={{ color: 'var(--text-secondary)', fontSize: '0.85rem', textAlign: 'center', padding: '1.5rem 0' }}>
                No saved profiles yet. Create one to quickly load your resume when tailoring.
              </p>
            ) : (
              <div style={{ display: 'flex', flexDirection: 'column', gap: '0.5rem', marginBottom: '1rem' }}>
                {profiles.map(p => (
                  <div key={p.id} className="glass-panel" style={{
                    display: 'flex',
                    alignItems: 'center',
                    gap: '0.75rem',
                    padding: '0.75rem',
                    background: p.is_default ? `${brand.primaryColor}08` : 'transparent',
                  }}>
                    <div style={{ flex: 1 }}>
                      <div style={{ fontWeight: 600, fontSize: '0.88rem', color: 'var(--text-primary)' }}>
                        {p.name}
                        {p.is_default && (
                          <span className="inline-badge" style={{
                            marginLeft: '0.4rem',
                            background: `${brand.primaryColor}20`,
                            color: brand.primaryColor,
                          }}>
                            Default
                          </span>
                        )}
                      </div>
                      {p.target_role && (
                        <div style={{ fontSize: '0.75rem', color: 'var(--text-secondary)' }}>{p.target_role}</div>
                      )}
                      <div style={{ fontSize: '0.7rem', color: 'var(--text-secondary)', marginTop: '0.2rem' }}>
                        {p.resume_text.length.toLocaleString()} characters
                      </div>
                    </div>

                    <button onClick={() => startEdit(p)} className="icon-btn" style={{ color: brand.primaryColor }}>
                      <i className="fa-solid fa-pen" />
                    </button>
                    <button onClick={() => handleDelete(p.id)} className="icon-btn" style={{ color: '#ef4444' }}>
                      <i className="fa-solid fa-trash" />
                    </button>
                  </div>
                ))}
              </div>
            )}

            <button
              onClick={startCreate}
              className="btn secondary-btn"
              style={{ width: '100%' }}
            >
              <i className="fa-solid fa-plus" /> New Profile
            </button>
          </>
        )}

        {/* Create / Edit Form */}
        {isFormOpen && (
          <div>
            <h4 style={{ margin: '0 0 1rem', color: 'var(--text-primary)', fontSize: '0.95rem' }}>
              {showCreate ? 'Create Profile' : 'Edit Profile'}
            </h4>

            <div style={{ display: 'flex', flexDirection: 'column', gap: '0.75rem' }}>
              <div>
                <label style={{ display: 'block', fontSize: '0.78rem', fontWeight: 600, color: 'var(--text-secondary)', marginBottom: '0.3rem' }}>
                  Profile Name *
                </label>
                <input
                  value={formName}
                  onChange={e => setFormName(e.target.value)}
                  placeholder="e.g., Senior Engineer, Product Manager"
                  style={{ width: '100%' }}
                />
              </div>

              <div>
                <label style={{ display: 'block', fontSize: '0.78rem', fontWeight: 600, color: 'var(--text-secondary)', marginBottom: '0.3rem' }}>
                  Target Role
                </label>
                <input
                  value={formRole}
                  onChange={e => setFormRole(e.target.value)}
                  placeholder="e.g., Full-Stack Developer, Data Scientist"
                  style={{ width: '100%' }}
                />
              </div>

              <div>
                <label style={{ display: 'block', fontSize: '0.78rem', fontWeight: 600, color: 'var(--text-secondary)', marginBottom: '0.3rem' }}>
                  Resume Text *
                </label>
                <textarea
                  value={formText}
                  onChange={e => setFormText(e.target.value)}
                  placeholder="Paste your resume text here..."
                  rows={8}
                  style={{ width: '100%', resize: 'vertical' }}
                />
              </div>

              <label style={{ display: 'flex', alignItems: 'center', gap: '0.5rem', fontSize: '0.82rem', color: 'var(--text-primary)', cursor: 'pointer' }}>
                <input
                  type="checkbox"
                  checked={formDefault}
                  onChange={e => setFormDefault(e.target.checked)}
                  style={{ accentColor: brand.primaryColor }}
                />
                Set as default profile
              </label>
            </div>

            <div style={{ display: 'flex', gap: '0.75rem', marginTop: '1.25rem' }}>
              <button
                onClick={cancelForm}
                className="btn ghost-btn"
              >
                Cancel
              </button>
              <button
                onClick={handleSave}
                disabled={saving}
                className="btn secondary-btn"
                style={{ flex: 1 }}
              >
                {saving ? 'Saving...' : showCreate ? 'Create' : 'Save Changes'}
              </button>
            </div>
          </div>
        )}
      </div>
    </div>
  );
}
