import { useState, useEffect, useCallback } from 'react';
import { useAuth } from '../context/SupabaseContext';

export interface ResumeProfile {
  id: string;
  user_id: string;
  name: string;
  target_role: string;
  resume_text: string;
  file_type: string | null;
  is_default: boolean;
  created_at: string;
  updated_at: string;
}

export function useResumeProfiles() {
  const { user, supabase } = useAuth();
  const [profiles, setProfiles] = useState<ResumeProfile[]>([]);
  const [isLoading, setIsLoading] = useState(false);

  const fetchProfiles = useCallback(async () => {
    if (!user) {
      setProfiles([]);
      return;
    }
    setIsLoading(true);
    const { data, error } = await supabase
      .from('resume_profiles')
      .select('*')
      .eq('user_id', user.id)
      .order('is_default', { ascending: false })
      .order('updated_at', { ascending: false });

    if (!error && data) {
      setProfiles(data);
    }
    setIsLoading(false);
  }, [user, supabase]);

  useEffect(() => {
    fetchProfiles();
  }, [fetchProfiles]);

  const createProfile = useCallback(async (profile: {
    name: string;
    target_role: string;
    resume_text: string;
    file_type?: string;
    is_default?: boolean;
  }) => {
    if (!user) return null;

    // If setting as default, unset other defaults first
    if (profile.is_default) {
      await supabase
        .from('resume_profiles')
        .update({ is_default: false })
        .eq('user_id', user.id)
        .eq('is_default', true);
    }

    const { data, error } = await supabase
      .from('resume_profiles')
      .insert({
        user_id: user.id,
        name: profile.name,
        target_role: profile.target_role,
        resume_text: profile.resume_text,
        file_type: profile.file_type || null,
        is_default: profile.is_default || profiles.length === 0, // first profile is default
      })
      .select()
      .single();

    if (!error && data) {
      await fetchProfiles();
      return data;
    }
    return null;
  }, [user, supabase, profiles.length, fetchProfiles]);

  const updateProfile = useCallback(async (id: string, updates: Partial<Pick<ResumeProfile, 'name' | 'target_role' | 'resume_text' | 'file_type' | 'is_default'>>) => {
    if (!user) return false;

    if (updates.is_default) {
      await supabase
        .from('resume_profiles')
        .update({ is_default: false })
        .eq('user_id', user.id)
        .eq('is_default', true);
    }

    const { error } = await supabase
      .from('resume_profiles')
      .update(updates)
      .eq('id', id)
      .eq('user_id', user.id);

    if (!error) {
      await fetchProfiles();
      return true;
    }
    return false;
  }, [user, supabase, fetchProfiles]);

  const deleteProfile = useCallback(async (id: string) => {
    if (!user) return false;

    const { error } = await supabase
      .from('resume_profiles')
      .delete()
      .eq('id', id)
      .eq('user_id', user.id);

    if (!error) {
      await fetchProfiles();
      return true;
    }
    return false;
  }, [user, supabase, fetchProfiles]);

  const getDefault = useCallback(() => {
    return profiles.find(p => p.is_default) || profiles[0] || null;
  }, [profiles]);

  return {
    profiles,
    isLoading,
    createProfile,
    updateProfile,
    deleteProfile,
    getDefault,
    refetch: fetchProfiles,
  };
}
