import React, { useState } from 'react';
import { useBrand } from '../context/BrandContext';
import { ResumeProfile } from '../hooks/useResumeProfiles';

interface ProfileSelectorProps {
  profiles: ResumeProfile[];
  isLoading: boolean;
  onSelect: (profile: ResumeProfile) => void;
  onManage: () => void;
}

export default function ProfileSelector({ profiles, isLoading, onSelect, onManage }: ProfileSelectorProps) {
  const brand = useBrand();
  const [isOpen, setIsOpen] = useState(false);

  if (isLoading) return null;
  if (profiles.length === 0) return null;

  const defaultProfile = profiles.find(p => p.is_default) || profiles[0];

  return (
    <div style={{ marginBottom: '1.25rem' }}>
      <div style={{
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'space-between',
        marginBottom: '0.5rem',
      }}>
        <span style={{ fontSize: '0.82rem', fontWeight: 600, color: 'var(--text-secondary)' }}>
          <i className="fa-solid fa-user-tie" style={{ marginRight: '0.4rem' }} />
          Saved Profiles ({profiles.length})
        </span>
        <button
          onClick={onManage}
          style={{
            background: 'none',
            border: 'none',
            color: brand.primaryColor,
            fontSize: '0.78rem',
            cursor: 'pointer',
            padding: 0,
          }}
        >
          Manage
        </button>
      </div>

      <div style={{ position: 'relative' }}>
        <button
          onClick={() => setIsOpen(!isOpen)}
          style={{
            width: '100%',
            padding: '0.65rem 0.75rem',
            borderRadius: '10px',
            border: `1px solid ${isOpen ? brand.primaryColor : 'var(--panel-border)'}`,
            background: 'var(--input-bg)',
            color: 'var(--text-primary)',
            fontSize: '0.85rem',
            textAlign: 'left',
            cursor: 'pointer',
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'space-between',
          }}
        >
          <span>
            <strong>{defaultProfile.name}</strong>
            {defaultProfile.target_role && (
              <span style={{ color: 'var(--text-secondary)', marginLeft: '0.5rem', fontSize: '0.78rem' }}>
                — {defaultProfile.target_role}
              </span>
            )}
          </span>
          <i className={`fa-solid fa-chevron-${isOpen ? 'up' : 'down'}`} style={{ fontSize: '0.7rem', color: 'var(--text-secondary)' }} />
        </button>

        {isOpen && (
          <div style={{
            position: 'absolute',
            top: '100%',
            left: 0,
            right: 0,
            marginTop: '4px',
            background: 'var(--panel-bg)',
            border: '1px solid var(--panel-border)',
            borderRadius: '10px',
            overflow: 'hidden',
            zIndex: 10,
            boxShadow: '0 4px 16px rgba(0,0,0,0.2)',
          }}>
            {profiles.map(p => (
              <button
                key={p.id}
                onClick={() => {
                  onSelect(p);
                  setIsOpen(false);
                }}
                style={{
                  width: '100%',
                  padding: '0.6rem 0.75rem',
                  background: p.is_default ? `${brand.primaryColor}10` : 'transparent',
                  border: 'none',
                  borderBottom: '1px solid var(--panel-border)',
                  color: 'var(--text-primary)',
                  fontSize: '0.82rem',
                  textAlign: 'left',
                  cursor: 'pointer',
                  display: 'flex',
                  alignItems: 'center',
                  gap: '0.5rem',
                }}
              >
                <div style={{ flex: 1 }}>
                  <div style={{ fontWeight: 600 }}>
                    {p.name}
                    {p.is_default && (
                      <span style={{
                        marginLeft: '0.4rem',
                        fontSize: '0.65rem',
                        background: `${brand.primaryColor}20`,
                        color: brand.primaryColor,
                        padding: '0.1rem 0.4rem',
                        borderRadius: '4px',
                      }}>
                        Default
                      </span>
                    )}
                  </div>
                  {p.target_role && (
                    <div style={{ color: 'var(--text-secondary)', fontSize: '0.75rem' }}>{p.target_role}</div>
                  )}
                </div>
                <span style={{ color: 'var(--text-secondary)', fontSize: '0.7rem' }}>
                  {p.resume_text.length.toLocaleString()} chars
                </span>
              </button>
            ))}
          </div>
        )}
      </div>
    </div>
  );
}
